import base64
import zlib
from datetime import datetime, timedelta
import uuid
from urllib.parse import urlencode
import requests


class SAMLServiceProvider:
    def __init__(self, sp_entity_id, sp_acs_url):
        self.sp_entity_id = sp_entity_id
        self.sp_acs_url = sp_acs_url
    
    def generate_request_id(self):
        return f"_{''.join(str(uuid.uuid4()).split('-'))}"
    
    def get_timestamp(self):
        return datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    
    def build_authn_request(self, destination_url, user_email=None, user_name=None, force_authn=False):
        request_id = self.generate_request_id()
        issue_instant = self.get_timestamp()
        
        saml_request = f"""<samlp:AuthnRequest xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{destination_url}"
    AssertionConsumerServiceURL="{self.sp_acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
    ForceAuthn="{str(force_authn).lower()}">
    <saml:Issuer>{self.sp_entity_id}</saml:Issuer>"""
        
        if user_email or user_name:
            saml_request += """
    <saml:Subject>"""
            if user_name:
                saml_request += f"""
        <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:unspecified">{user_name}</saml:NameID>"""
            if user_email:
                saml_request += f"""
        <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
            <saml:SubjectConfirmationData NotOnOrAfter="{(datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')}"
                Recipient="{self.sp_acs_url}"
                InResponseTo="{request_id}"/>
        </saml:SubjectConfirmation>"""
            saml_request += """
    </saml:Subject>"""
        
        saml_request += """
    <samlp:NameIDPolicy Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
    <samlp:RequestedAuthnContext Comparison="exact">
        <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
    </samlp:RequestedAuthnContext>
</samlp:AuthnRequest>"""
        
        return saml_request
    
    def encode_saml_request(self, saml_request):
        compressed = zlib.compress(saml_request.encode('utf-8'))[2:-4]
        encoded = base64.b64encode(compressed).decode('utf-8')
        return encoded
    
    def build_redirect_url(self, destination_url, encoded_request, relay_state=None):
        params = {'SAMLRequest': encoded_request}
        if relay_state:
            params['RelayState'] = relay_state
        return f"{destination_url}?{urlencode(params)}"
    
    def send_authn_request_post(self, destination_url, user_email=None, user_name=None, 
                                relay_state=None, additional_attributes=None):
        saml_request = self.build_authn_request(destination_url, user_email, user_name)
        
        if additional_attributes:
            attribute_statement = """
    <saml:AttributeStatement>"""
            for attr_name, attr_value in additional_attributes.items():
                attribute_statement += f"""
        <saml:Attribute Name="{attr_name}">
            <saml:AttributeValue>{attr_value}</saml:AttributeValue>
        </saml:Attribute>"""
            attribute_statement += """
    </saml:AttributeStatement>"""
            saml_request = saml_request.replace('</samlp:AuthnRequest>', 
                                                attribute_statement + '\n</samlp:AuthnRequest>')
        
        encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
        
        post_data = {'SAMLRequest': encoded_request}
        if relay_state:
            post_data['RelayState'] = relay_state
        
        response = requests.post(destination_url, data=post_data, allow_redirects=True)
        return response
    
    def send_authn_request_redirect(self, destination_url, user_email=None, user_name=None, 
                                    relay_state=None):
        saml_request = self.build_authn_request(destination_url, user_email, user_name)
        encoded_request = self.encode_saml_request(saml_request)
        redirect_url = self.build_redirect_url(destination_url, encoded_request, relay_state)
        
        response = requests.get(redirect_url, allow_redirects=True)
        return response
    
    def create_saml_post_form(self, destination_url, user_email=None, user_name=None, 
                             relay_state=None, additional_attributes=None):
        saml_request = self.build_authn_request(destination_url, user_email, user_name)
        
        if additional_attributes:
            attribute_statement = """
    <saml:AttributeStatement>"""
            for attr_name, attr_value in additional_attributes.items():
                attribute_statement += f"""
        <saml:Attribute Name="{attr_name}">
            <saml:AttributeValue>{attr_value}</saml:AttributeValue>
        </saml:Attribute>"""
            attribute_statement += """
    </saml:AttributeStatement>"""
            saml_request = saml_request.replace('</samlp:AuthnRequest>', 
                                                attribute_statement + '\n</samlp:AuthnRequest>')
        
        encoded_request = base64.b64encode(saml_request.encode('utf-8')).decode('utf-8')
        
        html_form = f"""<!DOCTYPE html>
<html>
<head>
    <title>SAML SSO</title>
</head>
<body onload="document.forms[0].submit()">
    <form method="post" action="{destination_url}">
        <input type="hidden" name="SAMLRequest" value="{encoded_request}" />"""
        
        if relay_state:
            html_form += f"""
        <input type="hidden" name="RelayState" value="{relay_state}" />"""
        
        html_form += """
        <noscript>
            <input type="submit" value="Continue" />
        </noscript>
    </form>
</body>
</html>"""
        
        return html_form


